 92→const distancePointToSegment = (px, py, x1, y1, x2, y2) => {
 93→    const dx = x2 - x1;
 94→    const dy = y2 - y1;
 95→    if(dx === 0 && dy === 0){
 96→        return Math.hypot(px - x1, py - y1);
 97→    }
 98→
 99→    const t = clamp(((px - x1) * dx + (py - y1) * dy) / (dx * dx + dy * dy), 0, 1);
100→    const cx = x1 + t * dx;
101→    const cy = y1 + t * dy;
102→    return Math.hypot(px - cx, py - cy);
103→};
