105→const isPointerNearDoodle = (pointerX, pointerY, doodle, radiusPx = ERASER_RADIUS_PX) => {
106→    if(!doodle?.points || doodle.points.length < 4){
107→        return false;
108→    }
109→
110→    const strokeWidth = Math.max(1, Number(doodle.strokeWidth) || 3);
111→    const hitDistance = radiusPx + strokeWidth * 0.5;
112→
113→    const points = doodle.points;
114→    for(let i = 0; i < points.length - 2; i += 2){
115→        const dist = distancePointToSegment(
116→            pointerX,
117→            pointerY,
118→            points[i],
119→            points[i + 1],
120→            points[i + 2],
121→            points[i + 3]
122→        );
123→        if(dist <= hitDistance){
124→            return true;
125→        }
126→    }
127→
128→    return false;
129→};
