133→const useEmojiImage = (emoji, resolution = 128) => {
134→    const [image, setImage] = useState(() => emojiCanvasCache.get(`${emoji}-${resolution}`) || null);
135→
136→    useEffect(() => {
137→        if(!emoji){
138→            setImage(null);
139→            return;
140→        }
141→
142→        const cacheKey = `${emoji}-${resolution}`;
143→        const cached = emojiCanvasCache.get(cacheKey);
144→        if(cached){
145→            setImage(cached);
146→            return;
147→        }
148→
149→        const canvas = document.createElement("canvas");
150→        canvas.width = resolution;
151→        canvas.height = resolution;
152→        const ctx = canvas.getContext("2d");
153→        ctx.clearRect(0, 0, resolution, resolution);
154→        ctx.textAlign = "center";
155→        ctx.textBaseline = "middle";
156→        ctx.font = `${Math.round(resolution * 0.78)}px "Segoe UI Emoji", "Apple Color Emoji", "Noto Color Emoji", sans-serif`;
157→        ctx.fillText(emoji, resolution / 2, resolution / 2);
158→
159→        const img = new window.Image();
160→        img.onload = () => {
161→            emojiCanvasCache.set(cacheKey, img);
162→            setImage(img);
163→        };
164→        img.src = canvas.toDataURL();
165→    }, [emoji, resolution]);
166→
167→    return image;
168→};
