258→const darkenColor = (hex, amount = 0.15) => {
259→    const raw = hex?.replace("#", "") || "fff4a8";
260→    const num = parseInt(raw.length === 3 ? raw.split("").map((c) => c + c).join("") : raw, 16);
261→    const r = Math.max(0, Math.round(((num >> 16) & 255) * (1 - amount)));
262→    const g = Math.max(0, Math.round(((num >> 8) & 255) * (1 - amount)));
263→    const b = Math.max(0, Math.round((num & 255) * (1 - amount)));
264→    return `rgb(${r},${g},${b})`;
265→};
