500→
501→    const endTimeMs = new Date(weekEnd).getTime();
502→    if(Number.isNaN(endTimeMs)){
503→        return "No reset scheduled";
504→    }
505→
506→    const diffMs = endTimeMs - nowMs;
507→    if(diffMs <= 0){
508→        return "Reset imminent";
509→    }
510→
511→    const totalSeconds = Math.floor(diffMs / 1000);
512→    const days = Math.floor(totalSeconds / 86400);
513→    const hours = Math.floor((totalSeconds % 86400) / 3600);
514→    const minutes = Math.floor((totalSeconds % 3600) / 60);
515→
516→    if(days > 0){
517→        return `${days} day${days === 1 ? "" : "s"}, ${hours} hour${hours === 1 ? "" : "s"}`;
518→    }
519→
520→    if(hours > 0){
521→        return `${hours} hour${hours === 1 ? "" : "s"}, ${minutes} min${minutes === 1 ? "" : "s"}`;
522→    }
523→
524→    return `${minutes} min${minutes === 1 ? "" : "s"}`;
