404→const PuffEffect = ({x, y, id, onComplete}) => {
405→    const [progress, setProgress] = useState(0);
406→    const startRef = useRef(null);
407→    const particlesRef = useRef(null);
408→
409→    if(!particlesRef.current){
410→        const count = 6 + Math.floor(Math.random() * 3);
411→        particlesRef.current = Array.from({length: count}, () => ({
412→            angle: Math.random() * Math.PI * 2,
413→            distance: 30 + Math.random() * 20,
414→            color: Math.random() > 0.5 ? "#a21caf" : "#e879f9"
415→        }));
416→    }
417→
418→    useEffect(() => {
419→        const duration = 500;
420→        let animId;
421→
422→        const animate = (timestamp) => {
423→            if(!startRef.current) startRef.current = timestamp;
424→            const elapsed = timestamp - startRef.current;
425→            const p = Math.min(elapsed / duration, 1);
426→            setProgress(p);
427→
428→            if(p < 1){
429→                animId = requestAnimationFrame(animate);
430→            } else {
431→                onComplete(id);
432→            }
433→        };
434→
435→        animId = requestAnimationFrame(animate);
436→        return () => cancelAnimationFrame(animId);
437→    }, [id, onComplete]);
438→
439→    const particles = particlesRef.current;
440→    const eased = 1 - Math.pow(1 - progress, 2);
441→
442→    return (
443→        <Group x={x} y={y} listening={false}>
444→            <Circle
445→                radius={eased * 28}
446→                stroke="#e879f9"
447→                strokeWidth={Math.max(0.5, 2 * (1 - progress))}
448→                opacity={1 - progress}
449→            />
450→            {particles.map((p, i) => (
451→                <Circle
452→                    key={i}
453→                    x={Math.cos(p.angle) * p.distance * eased}
454→                    y={Math.sin(p.angle) * p.distance * eased}
455→                    radius={Math.max(0.5, 3.5 * (1 - progress))}
456→                    fill={p.color}
457→                    opacity={1 - progress}
458→                />
459→            ))}
460→        </Group>
461→    );
462→};
